import java.util.*;class DoublyMovie{static class N{String t,d;int y;double r;N next,prev;N(String t,String d,int y,double r){this.t=t;this.d=d;this.y=y;this.r=r;}}static N head;static void add(String t,String d,int y,double r){N n=new N(t,d,y,r);if(head==null)head=n;else{head.prev=n;n.next=head;head=n;}}static void display(){N c=head;while(c!=null){System.out.println(c.t+" "+c.d+" "+c.y+" "+c.r);c=c.next;}}public static void main(String[] a){add("M1","D1",2020,4.5);add("M2","D2",2021,4.0);display();}}